parameters.jsCode:
// Obtener datos del input (n8n style)
const input = $input.first().json;

// Variables
const nombre = $('Edit Fields').first().json.Nombre || "Usuario";
const rol = input.Role || "Profesional";
const experiencia = $('Edit Fields').first().json['Experiencia (Años)'] || "N/A";
const disponibilidad = $('Edit Fields').first().json.Disponibilidad || "N/A";
const motivacion = $('Edit Fields').first().json.Motivacion || "crecer profesionalmente";

// Subject del correo
const subject = `Bienvenido a DipusAI, ${nombre}`;

// Body del correo (estilo persuasivo profesional)
const body = `
│ Estimado/a ${nombre} │

Mi nombre es JesusMiguel, y quiero darte la bienvenida personalmente a **DipusAI**.  
Es un gusto contar contigo como **${rol}**, y acompañarte en este camino de crecimiento profesional.

Sabemos que te encuentras en una etapa inicial de tu carrera (${experiencia}), y precisamente por eso creemos que este es el mejor momento para impulsarte con las herramientas, el acompañamiento y la visión correcta para que puedas **superarte y evolucionar rápidamente**.

✨ Imagina formar parte de un entorno donde:
- Tu aprendizaje es prioridad.
- Tu motivación (${motivacion}) se transforma en resultados reales.
- Cada proyecto te acerca un paso más a tu mejor versión profesional.

Tu disponibilidad de **${disponibilidad}** nos permitirá integrarte de manera ágil y comenzar a trabajar en objetivos claros desde el primer momento.


────────────────────────────

Equipo de trabajo de DipusAI.
`;

// Retornar output
return [
  {
    json: {
      Subject: subject,
      Body: body.trim()
    }
  }
];

